overview-comment.usage:
import { ColorInput } from '@razorpay/blade/components';

// Controlled usage with opacity
<ColorInput
  label="Background Color"
  value={{ hex: 'FF5733', opacity: 80 }}
  onChange={({ name, value }) => {
    console.log(value.hex);     // 'FF5733'
    console.log(value.opacity); // 80
  }}
  showOpacity={true}
  size="medium"
  validationState="none"
/>

// Uncontrolled usage without opacity
<ColorInput
  label="Border Color"
  defaultValue={{ hex: '000000', opacity: 100 }}
  showOpacity={false}
  onChange={({ name, value }) => console.log(value.hex)}
/>
